import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum AppMode {
  ONBOARDING = 'ONBOARDING',
  IDLE = 'IDLE',
  FOCUS = 'FOCUS',
  BREAK_SHORT = 'BREAK_SHORT',
  BREAK_LONG = 'BREAK_LONG',
  VERIFY_TASK = 'VERIFY_TASK',
  PUNISHMENT = 'PUNISHMENT',
  SETTINGS = 'SETTINGS',
}

export interface UserProfile {
  name: string;
  major: string;
  weakness: string;
  ambition: string;
  enemy: string; // The "ex" or rival
}

export interface SessionConfig {
  focusDuration: number; // minutes
  shortBreakDuration: number; // minutes
  longBreakDuration: number; // minutes
  sessionsBeforeLongBreak: number;
}

export interface SessionData {
  timestamp: number;
  duration: number; // seconds
  type: 'FOCUS' | 'BREAK';
  completed: boolean;
  task?: string;
}

export interface VerificationResult {
  success: boolean;
  message: string;
}

export interface InsultContent {
  text: string;
  imageBase64?: string;
}

// Simple oscillator based alarm to avoid external assets
let audioContext: AudioContext | null = null;
let oscillator: OscillatorNode | null = null;
let gainNode: GainNode | null = null;

const initAudio = () => {
  if (!audioContext) {
    audioContext = new (window.AudioContext || (window as any).webkitAudioContext)();
  }
};

export const playAlarm = () => {
  initAudio();
  if (!audioContext) return;
  if (oscillator) return; // Already playing

  oscillator = audioContext.createOscillator();
  gainNode = audioContext.createGain();

  oscillator.type = 'sawtooth';
  oscillator.frequency.setValueAtTime(440, audioContext.currentTime); // A4

  // Modulate frequency for siren effect
  oscillator.frequency.linearRampToValueAtTime(880, audioContext.currentTime + 0.5);
  oscillator.frequency.linearRampToValueAtTime(440, audioContext.currentTime + 1.0);

  // LFO for the siren modulation loop
  const lfo = audioContext.createOscillator();
  lfo.type = 'square';
  lfo.frequency.value = 4; // 4 Hz flash rate match
  const lfoGain = audioContext.createGain();
  lfoGain.gain.value = 500;
  lfo.connect(lfoGain);
  lfoGain.connect(oscillator.frequency);
  lfo.start();

  gainNode.gain.setValueAtTime(0.5, audioContext.currentTime);

  oscillator.connect(gainNode);
  gainNode.connect(audioContext.destination);
  oscillator.start();
};

export const stopAlarm = () => {
  if (oscillator) {
    try {
      oscillator.stop();
      oscillator.disconnect();
    } catch (e) {
      console.error(e);
    }
    oscillator = null;
  }
  if (gainNode) {
    gainNode.disconnect();
    gainNode = null;
  }
};

import { GoogleGenAI, Type } from "@google/genai";
import { UserProfile, InsultContent } from "../types";
import { SYSTEM_INSTRUCTION_INSULT, SYSTEM_INSTRUCTION_VERIFY, SYSTEM_INSTRUCTION_PUNISHMENT } from "../constants";

// Helper to get AI instance safely
const getAI = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) throw new Error("API Key missing");
  return new GoogleGenAI({ apiKey });
};

export const generateInsult = async (profile: UserProfile, currentTask: string): Promise<InsultContent> => {
  try {
    const ai = getAI();

    // 1. Generate Text
    const prompt = `
    User Profile:
    Name: ${profile.name}
    Major/Field: ${profile.major}
    Weakness: ${profile.weakness}
    Ambition: ${profile.ambition}
    Rival/Enemy: ${profile.enemy}

    Current Task they should be doing: ${currentTask}

    Generate a brutal, personalized insult/threat based on the prompt instructions.
    `;

    const textResponse = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: prompt,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION_INSULT,
        temperature: 1.2, // High creativity for insults
      }
    });

    const insultText = textResponse.text || "You are wasting space. Get to work.";

    // 2. Generate Image (Parallel or sequential)
    // Using flash-image for speed
    let imageBase64: string | undefined;
    try {
        const imagePrompt = `Dark, depressive, horror-style, abstract art representing: ${insultText}. High contrast, red and black.`;
        const imageResponse = await ai.models.generateContent({
            model: 'gemini-2.5-flash-image', // Nano banana
            contents: imagePrompt,
            config: {
                // No responseMimeType for this model as per docs
            }
        });

        // Extract image
        // The output response may contain both image and text parts; iterate to find image
        if (imageResponse.candidates?.[0]?.content?.parts) {
            for (const part of imageResponse.candidates[0].content.parts) {
                if (part.inlineData) {
                    imageBase64 = part.inlineData.data;
                    break;
                }
            }
        }
    } catch (imgError) {
        console.warn("Failed to generate image insult", imgError);
    }

    return {
      text: insultText,
      imageBase64: imageBase64 ? `data:image/png;base64,${imageBase64}` : undefined
    };

  } catch (error) {
    console.error("Insult gen failed:", error);
    return { text: "Work harder. The AI is judging your connection." };
  }
};

export const checkAttention = async (base64Image: string): Promise<boolean> => {
  try {
    const ai = getAI();
    // Simple Yes/No check on the image
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: {
        parts: [
            { inlineData: { mimeType: 'image/jpeg', data: base64Image } },
            { text: "Is there a person's face clearly visible and looking roughly towards the screen/camera? Answer ONLY 'YES' or 'NO'." }
        ]
      },
      config: {
          temperature: 0,
          maxOutputTokens: 10
      }
    });

    const text = response.text?.trim().toUpperCase();
    return text?.includes("YES") || false;
  } catch (error) {
    // If API fails, default to true (attentive) to avoid false alarms due to network
    console.error("Attention check failed", error);
    return true;
  }
};

export const verifyTaskCompletion = async (task: string, proofDescription: string, proofImageBase64?: string): Promise<{success: boolean, message: string}> => {
    const ai = getAI();

    const parts: any[] = [{ text: `Task: ${task}. User Description: ${proofDescription}` }];
    if (proofImageBase64) {
        // Strip prefix if present
        const data = proofImageBase64.replace(/^data:image\/\w+;base64,/, "");
        parts.push({ inlineData: { mimeType: 'image/jpeg', data } });
    }

    const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash',
        contents: { parts },
        config: {
            systemInstruction: SYSTEM_INSTRUCTION_VERIFY,
            responseMimeType: 'application/json',
            responseSchema: {
                type: Type.OBJECT,
                properties: {
                    success: { type: Type.BOOLEAN },
                    message: { type: Type.STRING }
                },
                required: ['success', 'message']
            }
        }
    });

    const json = JSON.parse(response.text || '{"success": false, "message": "Failed to verify"}');
    return json;
};

export const generatePunishment = async (): Promise<string> => {
    const ai = getAI();
    const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash',
        contents: "Give me a punishment.",
        config: {
            systemInstruction: SYSTEM_INSTRUCTION_PUNISHMENT,
        }
    });
    return response.text || "Do 50 Pushups.";
};

export const verifyPunishment = async (proofImageBase64: string): Promise<boolean> => {
     try {
        const ai = getAI();
        const data = proofImageBase64.replace(/^data:image\/\w+;base64,/, "");
        const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash',
        contents: {
            parts: [
                { inlineData: { mimeType: 'image/jpeg', data } },
                { text: "Does this image show a person doing a physical exercise or looking exhausted/punished? Answer YES or NO." }
            ]
        },
        config: { temperature: 0 }
        });

        const text = response.text?.trim().toUpperCase();
        return text?.includes("YES") || false;
    } catch (e) {
        return true; // Fail open
    }
}

import React from 'react';
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, Cell } from 'recharts';
import { SessionData } from '../types';

interface StatsProps {
  history: SessionData[];
  onClose: () => void;
}

export const Stats: React.FC<StatsProps> = ({ history, onClose }) => {
  // Aggregate data by date
  const dataMap = history.reduce((acc, session) => {
    if (session.type === 'FOCUS' && session.completed) {
      const date = new Date(session.timestamp).toLocaleDateString();
      if (!acc[date]) acc[date] = 0;
      acc[date] += session.duration / 60; // minutes
    }
    return acc;
  }, {} as Record<string, number>);

  const data = Object.entries(dataMap).map(([date, minutes]) => ({
    date,
    minutes: Math.round(minutes)
  })).slice(-7); // Last 7 days

  const totalFocusTime = Math.round(history.reduce((acc, s) => s.type === 'FOCUS' && s.completed ? acc + s.duration : acc, 0) / 60);

  return (
    <div className="absolute inset-0 bg-void-black/95 z-50 flex flex-col items-center justify-center p-8 backdrop-blur-md">
      <div className="w-full max-w-4xl bg-dim-gray border border-gray-700 p-6 rounded-lg shadow-2xl">
        <div className="flex justify-between items-center mb-6">
          <h2 className="text-2xl font-bold text-white uppercase tracking-wider">Performance Record</h2>
          <button onClick={onClose} className="text-gray-400 hover:text-white uppercase">Close [X]</button>
        </div>

        <div className="grid grid-cols-2 gap-4 mb-8">
            <div className="bg-void-black p-4 rounded border border-gray-800">
                <p className="text-gray-400 text-sm uppercase">Total Focus Time</p>
                <p className="text-4xl font-mono text-danger-red">{totalFocusTime} <span className="text-base text-gray-500">mins</span></p>
            </div>
            <div className="bg-void-black p-4 rounded border border-gray-800">
                <p className="text-gray-400 text-sm uppercase">Sessions Completed</p>
                <p className="text-4xl font-mono text-white">{history.filter(s => s.type === 'FOCUS' && s.completed).length}</p>
            </div>
        </div>

        <div className="h-64 w-full">
            <ResponsiveContainer width="100%" height="100%">
            <BarChart data={data}>
                <XAxis dataKey="date" stroke="#666" fontSize={12} tickLine={false} axisLine={false} />
                <YAxis stroke="#666" fontSize={12} tickLine={false} axisLine={false} />
                <Tooltip 
                    contentStyle={{ backgroundColor: '#000', border: '1px solid #333' }}
                    itemStyle={{ color: '#fff' }}
                    cursor={{fill: 'rgba(255, 255, 255, 0.05)'}}
                />
                <Bar dataKey="minutes" fill="#ff0000" radius={[4, 4, 0, 0]}>
                   {data.map((entry, index) => (
                      <Cell key={`cell-${index}`} fill={index === data.length - 1 ? '#ff0000' : '#333'} />
                    ))}
                </Bar>
            </BarChart>
            </ResponsiveContainer>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useRef, useCallback } from 'react';
import { 
    Play, Pause, RotateCcw, Settings as SettingsIcon, 
    Camera, Eye, AlertTriangle, TrendingUp, CheckSquare, XSquare
} from 'lucide-react';
import { AppMode, UserProfile, SessionConfig, SessionData, InsultContent } from './types';
import { DEFAULT_CONFIG, ATTENTION_CHECK_INTERVAL_MS, INSULT_REFRESH_INTERVAL_MS, ALLOWED_DISTRACTION_TIME_MS } from './constants';
import * as GeminiService from './services/gemini';
import { playAlarm, stopAlarm } from './utils/audio';
import { Stats } from './components/Stats';

// --- Sub-Components ---

const Onboarding: React.FC<{ onComplete: (profile: UserProfile) => void }> = ({ onComplete }) => {
  const [data, setData] = useState<UserProfile>({ name: '', major: '', weakness: '', ambition: '', enemy: '' });

  return (
    <div className="flex flex-col items-center justify-center min-h-screen p-4 bg-void-black text-white max-w-lg mx-auto">
      <h1 className="text-4xl font-black mb-2 text-danger-red uppercase tracking-widest text-center">Identity Check</h1>
      <p className="mb-8 text-gray-400 text-center">Tell me who you are so I can hurt you accurately.</p>

      <div className="w-full space-y-4">
        <input 
          placeholder="Name"
          className="w-full bg-dim-gray border border-gray-700 p-4 rounded text-white focus:border-danger-red outline-none transition-colors"
          onChange={e => setData({...data, name: e.target.value})}
        />
        <input 
          placeholder="Major / Field of Study"
          className="w-full bg-dim-gray border border-gray-700 p-4 rounded text-white focus:border-danger-red outline-none transition-colors"
          onChange={e => setData({...data, major: e.target.value})}
        />
         <input 
          placeholder="Biggest Weakness / Insecurity"
          className="w-full bg-dim-gray border border-gray-700 p-4 rounded text-white focus:border-danger-red outline-none transition-colors"
          onChange={e => setData({...data, weakness: e.target.value})}
        />
         <input 
          placeholder="What do you want to achieve?"
          className="w-full bg-dim-gray border border-gray-700 p-4 rounded text-white focus:border-danger-red outline-none transition-colors"
          onChange={e => setData({...data, ambition: e.target.value})}
        />
         <input 
          placeholder="Name of your Rival/Ex (The Enemy)"
          className="w-full bg-dim-gray border border-gray-700 p-4 rounded text-white focus:border-danger-red outline-none transition-colors"
          onChange={e => setData({...data, enemy: e.target.value})}
        />

        <button 
          onClick={() => {
              if(Object.values(data).every(s => s.length > 0)) onComplete(data);
              else alert("Fill everything out. Don't be lazy already.");
          }}
          className="w-full bg-danger-red hover:bg-red-700 text-white font-bold py-4 rounded uppercase tracking-wider mt-4 transition-colors"
        >
          Initialize Protocol
        </button>
      </div>
    </div>
  );
};

// --- Main App Component ---

const App: React.FC = () => {
  // --- State ---
  const [mode, setMode] = useState<AppMode>(AppMode.ONBOARDING);
  const [profile, setProfile] = useState<UserProfile | null>(null);
  const [config, setConfig] = useState<SessionConfig>(DEFAULT_CONFIG);
  const [timeLeft, setTimeLeft] = useState(DEFAULT_CONFIG.focusDuration * 60);
  const [isRunning, setIsRunning] = useState(false);
  const [sessionCount, setSessionCount] = useState(0);
  const [currentTask, setCurrentTask] = useState('');

  // Monitoring
  const [isDistracted, setIsDistracted] = useState(false);
  const [lastAttentiveTime, setLastAttentiveTime] = useState(Date.now());
  const videoRef = useRef<HTMLVideoElement>(null);
  const [cameraActive, setCameraActive] = useState(false);

  // Content
  const [insult, setInsult] = useState<InsultContent | null>(null);
  const [punishment, setPunishment] = useState<string>('');

  // Verification
  const [verifyText, setVerifyText] = useState('');
  const [verificationLoading, setVerificationLoading] = useState(false);

  // Stats
  const [history, setHistory] = useState<SessionData[]>([]);
  const [showStats, setShowStats] = useState(false);

  // --- Effects ---

  // Load from storage
  useEffect(() => {
    const saved = localStorage.getItem('lock_in_data');
    if (saved) {
      const parsed = JSON.parse(saved);
      if (parsed.profile) {
        setProfile(parsed.profile);
        setMode(AppMode.IDLE);
      }
      if (parsed.history) setHistory(parsed.history);
      if (parsed.config) setConfig(parsed.config);
    }
  }, []);

  // Save to storage
  useEffect(() => {
    if (profile) {
      localStorage.setItem('lock_in_data', JSON.stringify({ profile, history, config }));
    }
  }, [profile, history, config]);

  // Timer Tick
  useEffect(() => {
    let interval: any;
    if (isRunning && timeLeft > 0) {
      interval = setInterval(() => {
        setTimeLeft(prev => prev - 1);
      }, 1000);
    } else if (timeLeft === 0 && isRunning) {
      handleTimerComplete();
    }
    return () => clearInterval(interval);
  }, [isRunning, timeLeft]);

  // Attention Monitoring Loop (Only in FOCUS mode)
  useEffect(() => {
    if (mode !== AppMode.FOCUS || !isRunning) return;

    // Check loop
    const checkInterval = setInterval(async () => {
        if (!videoRef.current) return;

        // Capture frame
        const canvas = document.createElement('canvas');
        canvas.width = 320;
        canvas.height = 240;
        const ctx = canvas.getContext('2d');
        ctx?.drawImage(videoRef.current, 0, 0, canvas.width, canvas.height);
        const base64 = canvas.toDataURL('image/jpeg', 0.5); // Low quality for speed

        // Strip prefix
        const data = base64.replace(/^data:image\/\w+;base64,/, "");

        const attentive = await GeminiService.checkAttention(data);

        if (attentive) {
            setLastAttentiveTime(Date.now());
            if (isDistracted) {
                setIsDistracted(false);
                stopAlarm();
            }
        }
    }, ATTENTION_CHECK_INTERVAL_MS);

    // Distraction Alarm Loop
    const alarmInterval = setInterval(() => {
        const timeSince = Date.now() - lastAttentiveTime;
        if (timeSince > ALLOWED_DISTRACTION_TIME_MS) {
            if (!isDistracted) {
                setIsDistracted(true);
                playAlarm();
            }
        }
    }, 1000);

    return () => {
        clearInterval(checkInterval);
        clearInterval(alarmInterval);
        stopAlarm();
        setIsDistracted(false);
    };
  }, [mode, isRunning, lastAttentiveTime, isDistracted]);

  // Insult Refresh Loop (Only in FOCUS mode)
  useEffect(() => {
    if (mode !== AppMode.FOCUS || !isRunning || !profile) return;

    // Initial insult
    if (!insult) {
       GeminiService.generateInsult(profile, currentTask).then(setInsult);
    }

    const interval = setInterval(() => {
        GeminiService.generateInsult(profile, currentTask).then(setInsult);
    }, INSULT_REFRESH_INTERVAL_MS);

    return () => clearInterval(interval);
  }, [mode, isRunning, profile, currentTask]);

  // --- Handlers ---

  const startCamera = async () => {
    try {
        const stream = await navigator.mediaDevices.getUserMedia({ video: { width: 320 } });
        if (videoRef.current) {
            videoRef.current.srcObject = stream;
            setCameraActive(true);
        }
    } catch (e) {
        alert("Camera required for monitoring. Enable it.");
    }
  };

  const handleStartSession = async () => {
    if (!currentTask.trim()) {
        alert("State your task. Don't hide.");
        return;
    }
    if (!cameraActive) await startCamera();

    setMode(AppMode.FOCUS);
    setTimeLeft(config.focusDuration * 60);
    setIsRunning(true);
    setLastAttentiveTime(Date.now());
  };

  const handleTimerComplete = () => {
    setIsRunning(false);
    stopAlarm();

    if (mode === AppMode.FOCUS) {
        setMode(AppMode.VERIFY_TASK);
    } else {
        // Break over
        setMode(AppMode.IDLE);
    }
  };

  const handleVerification = async (hasImage: boolean, imageData?: string) => {
      setVerificationLoading(true);
      try {
          const result = await GeminiService.verifyTaskCompletion(currentTask, verifyText, imageData);
          if (result.success) {
              // Success
              setHistory(prev => [...prev, {
                  timestamp: Date.now(),
                  duration: config.focusDuration * 60,
                  type: 'FOCUS',
                  completed: true,
                  task: currentTask
              }]);

              const nextSessions = sessionCount + 1;
              setSessionCount(nextSessions);

              if (nextSessions >= config.sessionsBeforeLongBreak) {
                  setMode(AppMode.BREAK_LONG);
                  setTimeLeft(config.longBreakDuration * 60);
                  setSessionCount(0);
              } else {
                  setMode(AppMode.BREAK_SHORT);
                  setTimeLeft(config.shortBreakDuration * 60);
              }
              setIsRunning(true);
          } else {
              // Fail
              const punishmentTask = await GeminiService.generatePunishment();
              setPunishment(punishmentTask);
              setMode(AppMode.PUNISHMENT);
          }
      } catch (e) {
          alert("Error verifying. I'll let it slide this time because I'm broken.");
          setMode(AppMode.IDLE);
      }
      setVerificationLoading(false);
  };

  const handlePunishmentVerify = async () => {
     // For simplicity, we assume they click a button to capture current camera frame
     if (!videoRef.current) return;
     const canvas = document.createElement('canvas');
     canvas.width = 320;
     canvas.height = 240;
     const ctx = canvas.getContext('2d');
     ctx?.drawImage(videoRef.current, 0, 0);
     const base64 = canvas.toDataURL('image/jpeg');

     setVerificationLoading(true);
     const valid = await GeminiService.verifyPunishment(base64);
     setVerificationLoading(false);

     if (valid) {
         setHistory(prev => [...prev, {
            timestamp: Date.now(),
            duration: config.focusDuration * 60,
            type: 'FOCUS',
            completed: false, // Punishment means session failed basically
            task: currentTask
        }]);
         setMode(AppMode.IDLE);
     } else {
         alert("That didn't look like punishment. Do it again.");
     }
  };

  // --- Render Helpers ---

  const formatTime = (seconds: number) => {
    const m = Math.floor(seconds / 60).toString().padStart(2, '0');
    const s = (seconds % 60).toString().padStart(2, '0');
    return `${m}:${s}`;
  };

  // --- Views ---

  if (mode === AppMode.ONBOARDING) {
      return <Onboarding onComplete={(p) => { setProfile(p); setMode(AppMode.IDLE); }} />;
  }

  return (
    <div className={`relative min-h-screen w-full flex flex-col ${isDistracted ? 'animate-flash' : 'bg-void-black'} text-white transition-colors duration-200`}>
        {/* Hidden Camera Feed */}
        <video ref={videoRef} autoPlay muted playsInline className="absolute top-2 right-2 w-32 opacity-20 hover:opacity-100 transition-opacity z-50 pointer-events-none border border-gray-800 rounded" />

        {/* Header */}
        <header className="p-6 flex justify-between items-center z-10 border-b border-gray-900 bg-void-black/80 backdrop-blur">
            <h1 className="text-2xl font-black tracking-widest text-danger-red italic">LOCK IN</h1>
            <div className="flex gap-4">
                <button onClick={() => setShowStats(true)} className="p-2 hover:bg-gray-800 rounded text-gray-400 hover:text-white transition-colors">
                    <TrendingUp size={24} />
                </button>
            </div>
        </header>

        {/* Main Content Area */}
        <main className="flex-1 flex flex-col items-center justify-center p-6 relative">

            {/* IDLE VIEW */}
            {mode === AppMode.IDLE && (
                <div className="w-full max-w-md space-y-8 animate-fade-in">
                    <div className="text-center space-y-2">
                        <p className="text-gray-400">Welcome back, <span className="text-white font-bold">{profile?.name}</span>.</p>
                        <p className="text-sm text-gray-500">Ready to stop disappointing your ancestors?</p>
                    </div>

                    <div className="space-y-4">
                        <label className="block text-sm font-bold uppercase text-gray-500">Task Objective</label>
                        <textarea 
                            value={currentTask}
                            onChange={(e) => setCurrentTask(e.target.value)}
                            placeholder="What exactly will you accomplish? Be specific."
                            className="w-full bg-dim-gray border border-gray-700 p-4 rounded text-white focus:border-danger-red outline-none min-h-[100px]"
                        />
                    </div>

                    <button 
                        onClick={handleStartSession}
                        className="w-full bg-danger-red hover:bg-red-700 text-white font-black py-6 rounded text-xl uppercase tracking-widest shadow-[0_0_20px_rgba(255,0,0,0.3)] hover:shadow-[0_0_30px_rgba(255,0,0,0.5)] transition-all"
                    >
                        INITIATE FOCUS
                    </button>

                    <div className="grid grid-cols-3 gap-2 text-center text-xs text-gray-600 mt-8">
                        <div>
                            <span className="block font-bold text-gray-400">{config.focusDuration}m</span>
                            Focus
                        </div>
                        <div>
                            <span className="block font-bold text-gray-400">{config.shortBreakDuration}m</span>
                            Short Break
                        </div>
                         <div>
                            <span className="block font-bold text-gray-400">{config.longBreakDuration}m</span>
                            Long Break
                        </div>
                    </div>
                </div>
