                                </p>
                             </>
                         ) : (
                             <p className="text-gray-500 animate-pulse">Analyzing your failures...</p>
                         )}
                    </div>

                    {/* Distraction Warning Overlay */}
                    {isDistracted && (
                         <div className="absolute inset-0 z-50 flex items-center justify-center bg-red-600/20 backdrop-blur-sm">
