// --- Main App Component ---

const App: React.FC = () => {
  // --- State ---
  const [mode, setMode] = useState<AppMode>(AppMode.ONBOARDING);
  const [profile, setProfile] = useState<UserProfile | null>(null);
  const [config, setConfig] = useState<SessionConfig>(DEFAULT_CONFIG);
  const [timeLeft, setTimeLeft] = useState(DEFAULT_CONFIG.focusDuration * 60);
  const [isRunning, setIsRunning] = useState(false);
  const [sessionCount, setSessionCount] = useState(0);
  const [currentTask, setCurrentTask] = useState('');

  // Monitoring
  const [isDistracted, setIsDistracted] = useState(false);
  const [lastAttentiveTime, setLastAttentiveTime] = useState(Date.now());
  const videoRef = useRef<HTMLVideoElement>(null);
  const [cameraActive, setCameraActive] = useState(false);

  // Content
  const [insult, setInsult] = useState<InsultContent | null>(null);
  const [punishment, setPunishment] = useState<string>('');

  // Verification
  const [verifyText, setVerifyText] = useState('');
  const [verificationLoading, setVerificationLoading] = useState(false);

  // Stats
  const [history, setHistory] = useState<SessionData[]>([]);
  const [showStats, setShowStats] = useState(false);

  // --- Effects ---

  // Load from storage
  useEffect(() => {
    const saved = localStorage.getItem('lock_in_data');
    if (saved) {
      const parsed = JSON.parse(saved);
      if (parsed.profile) {
        setProfile(parsed.profile);
        setMode(AppMode.IDLE);
      }
      if (parsed.history) setHistory(parsed.history);
      if (parsed.config) setConfig(parsed.config);
    }
  }, []);

  // Save to storage
  useEffect(() => {
    if (profile) {
      localStorage.setItem('lock_in_data', JSON.stringify({ profile, history, config }));
    }
  }, [profile, history, config]);

  // Timer Tick
  useEffect(() => {
    let interval: any;
    if (isRunning && timeLeft > 0) {
      interval = setInterval(() => {
        setTimeLeft(prev => prev - 1);
      }, 1000);
    } else if (timeLeft === 0 && isRunning) {
      handleTimerComplete();
    }
    return () => clearInterval(interval);
  }, [isRunning, timeLeft]);

  // Attention Monitoring Loop (Only in FOCUS mode)
  useEffect(() => {
    if (mode !== AppMode.FOCUS || !isRunning) return;

    // Check loop
    const checkInterval = setInterval(async () => {
        if (!videoRef.current) return;

        // Capture frame
        const canvas = document.createElement('canvas');
        canvas.width = 320;
        canvas.height = 240;
        const ctx = canvas.getContext('2d');
        ctx?.drawImage(videoRef.current, 0, 0, canvas.width, canvas.height);
        const base64 = canvas.toDataURL('image/jpeg', 0.5); // Low quality for speed

        // Strip prefix
        const data = base64.replace(/^data:image\/\w+;base64,/, "");

        const attentive = await GeminiService.checkAttention(data);

        if (attentive) {
            setLastAttentiveTime(Date.now());
            if (isDistracted) {
                setIsDistracted(false);
                stopAlarm();
            }
        }
    }, ATTENTION_CHECK_INTERVAL_MS);

    // Distraction Alarm Loop
    const alarmInterval = setInterval(() => {
        const timeSince = Date.now() - lastAttentiveTime;
        if (timeSince > ALLOWED_DISTRACTION_TIME_MS) {
            if (!isDistracted) {
                setIsDistracted(true);
                playAlarm();
            }
        }
    }, 1000);

    return () => {
        clearInterval(checkInterval);
        clearInterval(alarmInterval);
        stopAlarm();
        setIsDistracted(false);
    };
  }, [mode, isRunning, lastAttentiveTime, isDistracted]);

  // Insult Refresh Loop (Only in FOCUS mode)
  useEffect(() => {
    if (mode !== AppMode.FOCUS || !isRunning || !profile) return;

    // Initial insult
    if (!insult) {
       GeminiService.generateInsult(profile, currentTask).then(setInsult);
    }

    const interval = setInterval(() => {
        GeminiService.generateInsult(profile, currentTask).then(setInsult);
    }, INSULT_REFRESH_INTERVAL_MS);

    return () => clearInterval(interval);
  }, [mode, isRunning, profile, currentTask]);

  // --- Handlers ---

  const startCamera = async () => {
    try {
        const stream = await navigator.mediaDevices.getUserMedia({ video: { width: 320 } });
        if (videoRef.current) {
            videoRef.current.srcObject = stream;
            setCameraActive(true);
        }
    } catch (e) {
        alert("Camera required for monitoring. Enable it.");
    }
  };

  const handleStartSession = async () => {
    if (!currentTask.trim()) {
        alert("State your task. Don't hide.");
        return;
    }
    if (!cameraActive) await startCamera();

    setMode(AppMode.FOCUS);
    setTimeLeft(config.focusDuration * 60);
    setIsRunning(true);
    setLastAttentiveTime(Date.now());
  };

  const handleTimerComplete = () => {
    setIsRunning(false);
    stopAlarm();

    if (mode === AppMode.FOCUS) {
        setMode(AppMode.VERIFY_TASK);
    } else {
        // Break over
        setMode(AppMode.IDLE);
    }
  };

  const handleVerification = async (hasImage: boolean, imageData?: string) => {
      setVerificationLoading(true);
      try {
          const result = await GeminiService.verifyTaskCompletion(currentTask, verifyText, imageData);
          if (result.success) {
              // Success
              setHistory(prev => [...prev, {
                  timestamp: Date.now(),
                  duration: config.focusDuration * 60,
                  type: 'FOCUS',
                  completed: true,
                  task: currentTask
              }]);

              const nextSessions = sessionCount + 1;
              setSessionCount(nextSessions);

              if (nextSessions >= config.sessionsBeforeLongBreak) {
                  setMode(AppMode.BREAK_LONG);
                  setTimeLeft(config.longBreakDuration * 60);
                  setSessionCount(0);
              } else {
                  setMode(AppMode.BREAK_SHORT);
                  setTimeLeft(config.shortBreakDuration * 60);
              }
              setIsRunning(true);
          } else {
              // Fail
              const punishmentTask = await GeminiService.generatePunishment();
              setPunishment(punishmentTask);
              setMode(AppMode.PUNISHMENT);
          }
      } catch (e) {
          alert("Error verifying. I'll let it slide this time because I'm broken.");
          setMode(AppMode.IDLE);
      }
      setVerificationLoading(false);
  };

  const handlePunishmentVerify = async () => {
     // For simplicity, we assume they click a button to capture current camera frame
     if (!videoRef.current) return;
     const canvas = document.createElement('canvas');
     canvas.width = 320;
     canvas.height = 240;
     const ctx = canvas.getContext('2d');
     ctx?.drawImage(videoRef.current, 0, 0);
     const base64 = canvas.toDataURL('image/jpeg');

     setVerificationLoading(true);
     const valid = await GeminiService.verifyPunishment(base64);
     setVerificationLoading(false);

     if (valid) {
         setHistory(prev => [...prev, {
            timestamp: Date.now(),
            duration: config.focusDuration * 60,
            type: 'FOCUS',
            completed: false, // Punishment means session failed basically
            task: currentTask
        }]);
         setMode(AppMode.IDLE);
     } else {
         alert("That didn't look like punishment. Do it again.");
     }
  };

  // --- Render Helpers ---

  const formatTime = (seconds: number) => {
    const m = Math.floor(seconds / 60).toString().padStart(2, '0');
    const s = (seconds % 60).toString().padStart(2, '0');
    return `${m}:${s}`;
  };

  // --- Views ---

  if (mode === AppMode.ONBOARDING) {
      return <Onboarding onComplete={(p) => { setProfile(p); setMode(AppMode.IDLE); }} />;
  }

  return (
    <div className={`relative min-h-screen w-full flex flex-col ${isDistracted ? 'animate-flash' : 'bg-void-black'} text-white transition-colors duration-200`}>
        {/* Hidden Camera Feed */}
        <video ref={videoRef} autoPlay muted playsInline className="absolute top-2 right-2 w-32 opacity-20 hover:opacity-100 transition-opacity z-50 pointer-events-none border border-gray-800 rounded" />

        {/* Header */}
        <header className="p-6 flex justify-between items-center z-10 border-b border-gray-900 bg-void-black/80 backdrop-blur">
            <h1 className="text-2xl font-black tracking-widest text-danger-red italic">LOCK IN</h1>
            <div className="flex gap-4">
                <button onClick={() => setShowStats(true)} className="p-2 hover:bg-gray-800 rounded text-gray-400 hover:text-white transition-colors">
                    <TrendingUp size={24} />
                </button>
            </div>
        </header>

        {/* Main Content Area */}
        <main className="flex-1 flex flex-col items-center justify-center p-6 relative">

            {/* IDLE VIEW */}
            {mode === AppMode.IDLE && (
                <div className="w-full max-w-md space-y-8 animate-fade-in">
                    <div className="text-center space-y-2">
                        <p className="text-gray-400">Welcome back, <span className="text-white font-bold">{profile?.name}</span>.</p>
                        <p className="text-sm text-gray-500">Ready to stop disappointing your ancestors?</p>
                    </div>

                    <div className="space-y-4">
                        <label className="block text-sm font-bold uppercase text-gray-500">Task Objective</label>
                        <textarea 
                            value={currentTask}
                            onChange={(e) => setCurrentTask(e.target.value)}
                            placeholder="What exactly will you accomplish? Be specific."
                            className="w-full bg-dim-gray border border-gray-700 p-4 rounded text-white focus:border-danger-red outline-none min-h-[100px]"
                        />
                    </div>

                    <button 
                        onClick={handleStartSession}
                        className="w-full bg-danger-red hover:bg-red-700 text-white font-black py-6 rounded text-xl uppercase tracking-widest shadow-[0_0_20px_rgba(255,0,0,0.3)] hover:shadow-[0_0_30px_rgba(255,0,0,0.5)] transition-all"
                    >
                        INITIATE FOCUS
                    </button>

                    <div className="grid grid-cols-3 gap-2 text-center text-xs text-gray-600 mt-8">
                        <div>
                            <span className="block font-bold text-gray-400">{config.focusDuration}m</span>
                            Focus
                        </div>
                        <div>
                            <span className="block font-bold text-gray-400">{config.shortBreakDuration}m</span>
                            Short Break
                        </div>
                         <div>
                            <span className="block font-bold text-gray-400">{config.longBreakDuration}m</span>
                            Long Break
                        </div>
                    </div>
                </div>
            )}

            {/* FOCUS VIEW */}
            {mode === AppMode.FOCUS && (
                <div className="w-full h-full flex flex-col items-center justify-center relative">
                    {/* Background Image / Insult */}
                    <div className="absolute inset-0 opacity-20 pointer-events-none z-0 overflow-hidden">
                        {insult?.imageBase64 && (
                            <img src={insult.imageBase64} alt="Atmosphere" className="w-full h-full object-cover transition-opacity duration-1000" />
                        )}
                        <div className="absolute inset-0 bg-gradient-to-t from-void-black via-transparent to-void-black" />
                    </div>

                    {/* Timer */}
                    <div className="z-10 text-center mb-12">
                         <div className="text-[12rem] font-black leading-none tracking-tighter tabular-nums drop-shadow-2xl">
                             {formatTime(timeLeft)}
                         </div>
                         <div className="text-red-500 font-bold uppercase tracking-[1em] animate-pulse">
                             Focusing
                         </div>
                    </div>

                    {/* Insult Card */}
                    <div className="z-10 max-w-2xl bg-black/60 backdrop-blur-sm border border-red-900/30 p-8 rounded-lg text-center transform transition-all duration-500">
                         {insult ? (
                             <>
                                <p className="text-xl md:text-2xl font-bold text-gray-200 leading-relaxed font-mono">
                                    "{insult.text}"
                                </p>
                             </>
                         ) : (
                             <p className="text-gray-500 animate-pulse">Analyzing your failures...</p>
                         )}
                    </div>

                    {/* Distraction Warning Overlay */}
                    {isDistracted && (
                         <div className="absolute inset-0 z-50 flex items-center justify-center bg-red-600/20 backdrop-blur-sm">
                             <div className="bg-void-black border-4 border-white p-12 text-center animate-bounce">
                                 <AlertTriangle size={64} className="mx-auto text-danger-red mb-4" />
                                 <h2 className="text-4xl font-black uppercase text-white mb-2">EYES ON SCREEN</h2>
                                 <p className="text-red-500 font-mono">The timer is watching you.</p>
                             </div>
                         </div>
                    )}
                </div>
            )}

            {/* BREAK VIEW */}
            {(mode === AppMode.BREAK_SHORT || mode === AppMode.BREAK_LONG) && (
                <div className="text-center z-10">
                     <h2 className="text-4xl font-bold text-green-500 mb-4">REST PROTOCOL</h2>
                     <div className="text-9xl font-mono mb-8">{formatTime(timeLeft)}</div>
                     <p className="text-gray-400 max-w-md mx-auto">
                         Don't get comfortable. The next session will be harder. 
                         {mode === AppMode.BREAK_LONG ? " Enjoy your long break." : " Just a quick sip of water."}
                     </p>
                </div>
            )}

            {/* VERIFICATION VIEW */}
