import { GoogleGenAI, Type } from "@google/genai";
import { UserProfile, InsultContent } from "../types";
import { SYSTEM_INSTRUCTION_INSULT, SYSTEM_INSTRUCTION_VERIFY, SYSTEM_INSTRUCTION_PUNISHMENT } from "../constants";

// Helper to get AI instance safely
const getAI = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) throw new Error("API Key missing");
  return new GoogleGenAI({ apiKey });
};

export const generateInsult = async (profile: UserProfile, currentTask: string): Promise<InsultContent> => {
  try {
    const ai = getAI();

    // 1. Generate Text
    const prompt = `
    User Profile:
    Name: ${profile.name}
    Major/Field: ${profile.major}
    Weakness: ${profile.weakness}
    Ambition: ${profile.ambition}
    Rival/Enemy: ${profile.enemy}

    Current Task they should be doing: ${currentTask}

    Generate a brutal, personalized insult/threat based on the prompt instructions.
    `;

    const textResponse = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: prompt,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION_INSULT,
        temperature: 1.2, // High creativity for insults
      }
    });

    const insultText = textResponse.text || "You are wasting space. Get to work.";

    // 2. Generate Image (Parallel or sequential)
    // Using flash-image for speed
    let imageBase64: string | undefined;
    try {
        const imagePrompt = `Dark, depressive, horror-style, abstract art representing: ${insultText}. High contrast, red and black.`;
        const imageResponse = await ai.models.generateContent({
            model: 'gemini-2.5-flash-image', // Nano banana
            contents: imagePrompt,
            config: {
                // No responseMimeType for this model as per docs
            }
        });

        // Extract image
        // The output response may contain both image and text parts; iterate to find image
        if (imageResponse.candidates?.[0]?.content?.parts) {
            for (const part of imageResponse.candidates[0].content.parts) {
                if (part.inlineData) {
                    imageBase64 = part.inlineData.data;
                    break;
                }
            }
        }
    } catch (imgError) {
        console.warn("Failed to generate image insult", imgError);
    }

    return {
      text: insultText,
      imageBase64: imageBase64 ? `data:image/png;base64,${imageBase64}` : undefined
    };

  } catch (error) {
    console.error("Insult gen failed:", error);
    return { text: "Work harder. The AI is judging your connection." };
  }
};

export const checkAttention = async (base64Image: string): Promise<boolean> => {
  try {
    const ai = getAI();
    // Prompt tuned for leniency on study posture, strictness on distractions
    const prompt = `
      Analyze this image of a student studying. 
      Return 'YES' if they appear to be working (looking at screen, reading notes/books, looking down at desk, typing). 
      Return 'NO' ONLY if:
      1. They are completely out of frame.
      2. They are visibly using a smartphone/phone.
      3. Their eyes are closed or head is down (sleeping).
      4. They are clearly looking away/talking to someone else for an extended period.

      Answer ONLY 'YES' or 'NO'.
    `;

    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: {
        parts: [
            { inlineData: { mimeType: 'image/jpeg', data: base64Image } },
            { text: prompt }
        ]
      },
      config: {
          temperature: 0,
          maxOutputTokens: 10
      }
    });

    const text = response.text?.trim().toUpperCase();
    return text?.includes("YES") || false;
  } catch (error) {
    // If API fails, default to true (attentive) to avoid false alarms due to network
    console.error("Attention check failed", error);
    return true;
  }
};

export const verifyTaskCompletion = async (task: string, proofDescription: string, proofImageBase64?: string): Promise<{success: boolean, message: string}> => {
    const ai = getAI();

    const parts: any[] = [{ text: `Task: ${task}. User Description: ${proofDescription}` }];
    if (proofImageBase64) {
        // Strip prefix if present
        const data = proofImageBase64.replace(/^data:image\/\w+;base64,/, "");
        parts.push({ inlineData: { mimeType: 'image/jpeg', data } });
    }

    const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash',
        contents: { parts },
        config: {
            systemInstruction: SYSTEM_INSTRUCTION_VERIFY,
            responseMimeType: 'application/json',
            responseSchema: {
                type: Type.OBJECT,
                properties: {
                    success: { type: Type.BOOLEAN },
                    message: { type: Type.STRING }
                },
                required: ['success', 'message']
            }
        }
    });

    const json = JSON.parse(response.text || '{"success": false, "message": "Failed to verify"}');
    return json;
};

export const generatePunishment = async (): Promise<string> => {
    const ai = getAI();
    const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash',
        contents: "Give me a punishment.",
        config: {
            systemInstruction: SYSTEM_INSTRUCTION_PUNISHMENT,
        }
    });
    return response.text || "Do 50 Pushups.";
};

export const verifyPunishment = async (proofImageBase64: string): Promise<boolean> => {
     try {
        const ai = getAI();
        const data = proofImageBase64.replace(/^data:image\/\w+;base64,/, "");
        const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash',
        contents: {
            parts: [
                { inlineData: { mimeType: 'image/jpeg', data } },
                { text: "Does this image show a person doing a physical exercise or looking exhausted/punished? Answer YES or NO." }
            ]
        },
        config: { temperature: 0 }
        });

        const text = response.text?.trim().toUpperCase();
        return text?.includes("YES") || false;
    } catch (e) {
        return true; // Fail open
    }
}

// Dissonant alarm to ensure discomfort
let audioContext: AudioContext | null = null;
let osc1: OscillatorNode | null = null;
let osc2: OscillatorNode | null = null;
let gainNode: GainNode | null = null;

const initAudio = () => {
  if (!audioContext) {
    audioContext = new (window.AudioContext || (window as any).webkitAudioContext)();
  }
};

export const playAlarm = () => {
  initAudio();
  if (!audioContext) return;
  if (osc1) return; // Already playing

  // Create gain node
  gainNode = audioContext.createGain();
  gainNode.gain.value = 0.8; // Loud but not clipping
  gainNode.connect(audioContext.destination);

  const now = audioContext.currentTime;

  // Oscillator 1: The "Root" Siren
  osc1 = audioContext.createOscillator();
  osc1.type = 'sawtooth'; // Harsh tone
  osc1.frequency.setValueAtTime(500, now);
  // Fast modulation
  osc1.frequency.linearRampToValueAtTime(1000, now + 0.2);
  osc1.frequency.linearRampToValueAtTime(500, now + 0.4);

  // Oscillator 2: The "Dissonant" Interval (Tritone-ish) to create anxiety
  osc2 = audioContext.createOscillator();
  osc2.type = 'square'; // Very harsh chiptune-like tone
  osc2.frequency.setValueAtTime(725, now); // ~F#5 (Tritone from C5 approx)
  // Counter-modulation
  osc2.frequency.linearRampToValueAtTime(300, now + 0.2);
  osc2.frequency.linearRampToValueAtTime(725, now + 0.4);

  // LFO to drive the loop of both frequencies
  const lfo = audioContext.createOscillator();
  lfo.type = 'square';
  lfo.frequency.value = 5; // 5Hz fast siren

  // Connect LFO to frequency parameters implies manual looping for Web Audio or simpler approach:
  // For simplicity and browser compatibility without complex graph, we use a looped buffer or just rely on the effect.
  // Actually, let's just use the LFO to gate the volume for a "stutter" effect which is annoying.

  const stutter = audioContext.createGain();
  stutter.gain.setValueAtTime(1, now);
  // We will just let the raw oscillators screech. The linearRamp above only happens once.
  // To make it loop, we need to set specific periodic waves or use an LFO connected to frequency.

  // Resetting to a simpler, reliable screeching LFO driven setup:

  // Re-configure Osc1
  osc1.disconnect();
  osc1 = audioContext.createOscillator();
  osc1.type = 'sawtooth';
  osc1.frequency.value = 800;

  // Re-configure Osc2
  osc2.disconnect();
  osc2 = audioContext.createOscillator();
  osc2.type = 'square';
  osc2.frequency.value = 1200; // Dissonant

  // Modulator
  const mod = audioContext.createOscillator();
  mod.type = 'sawtooth';
  mod.frequency.value = 8; // 8Hz modulation (very fast)

  const modGain = audioContext.createGain();
  modGain.gain.value = 500; // Swing range

  mod.connect(modGain);
  modGain.connect(osc1.frequency);
  modGain.connect(osc2.frequency);

  mod.start();
  osc1.start();
  osc2.start();

  osc1.connect(gainNode);
  osc2.connect(gainNode);

  // Store references to stop later (we need to stop the modulator too, but for simplicity of cleanup...)
  // We'll attach the mod to the osc1 object to clean it up
  (osc1 as any)._mod = mod;
};

export const stopAlarm = () => {
  if (osc1) {
    try {
      if ((osc1 as any)._mod) (osc1 as any)._mod.stop();
      osc1.stop();
      osc1.disconnect();
    } catch (e) { console.error(e); }
    osc1 = null;
  }
  if (osc2) {
    try {
      osc2.stop();
      osc2.disconnect();
    } catch (e) { console.error(e); }
    osc2 = null;
  }
  if (gainNode) {
    gainNode.disconnect();
    gainNode = null;
  }
};

