import * as tf from '@tensorflow/tfjs';
import * as blazeface from '@tensorflow-models/blazeface';
import * as cocoSsd from '@tensorflow-models/coco-ssd';
import { VisionStatus } from '../types';

let faceModel: blazeface.BlazeFaceModel | null = null;
let objModel: cocoSsd.ObjectDetection | null = null;
let loadingPromise: Promise<void> | null = null;

export const loadModel = async () => {
  if (faceModel && objModel) return;
  if (loadingPromise) return loadingPromise;

  loadingPromise = (async () => {
      try {
        await tf.ready();
        console.log("TFJS Ready");

        // Load both models in parallel
        const [loadedFace, loadedObj] = await Promise.all([
             blazeface.load(),
             cocoSsd.load({ base: 'lite_mobilenet_v2' }) // Use lite version for speed
        ]);

        faceModel = loadedFace;
        objModel = loadedObj;
        console.log("Vision Models Loaded");
      } catch (e) {
          console.error("Failed to load Vision models", e);
      }
  })();

  return loadingPromise;
};

export const monitorUser = async (video: HTMLVideoElement): Promise<VisionStatus> => {
  const result: VisionStatus = {
      isPresent: false,
      hasPhone: false,
      isSlouching: false
  };

  if (!faceModel || !objModel) return result;

  try {
      // 1. Object Detection (Phone)
      // We don't need to run this EVERY frame if it's too slow, but MobileNet V2 Lite is usually fine
      const objects = await objModel.detect(video);
      const phone = objects.find(obj => obj.class === 'cell phone' && obj.score > 0.5); // increased confidence
      if (phone) {
          result.hasPhone = true;
      }

      // 2. Face Detection (Presence & Posture)
      const faces = await faceModel.estimateFaces(video, false);

      if (faces.length > 0) {
          result.isPresent = true;

          // Posture Heuristic
          // We assume sitting upright puts the face in the upper/middle portion of the frame.
          // Slouching = Sliding down (Face low) or Leaning back (Face small)

          // BlazeFace predictions are objects with topLeft and bottomRight properties
          const face = faces[0] as any; 
          const start = face.topLeft as [number, number];
          const end = face.bottomRight as [number, number];

          const faceY = (start[1] + end[1]) / 2; // Center Y
          const faceHeight = end[1] - start[1];
          const videoHeight = video.videoHeight || 240;

          // Check 1: Face too low (Sliding down chair)
          // If center of face is in the bottom 30% of the screen
          if (faceY > videoHeight * 0.70) {
              result.isSlouching = true;
          }

          // Check 2: Face too small (Leaning way back)
          // Normal face usually takes up > 15-20% of height. If it's < 10%, they are far.
          if (faceHeight < videoHeight * 0.10) {
              result.isSlouching = true;
          }
      }

  } catch (e) {
      console.warn("Detection error", e);
  }

  return result;
};

import { GoogleGenAI, Type } from "@google/genai";
import { UserProfile, InsultContent } from "../types";
import { SYSTEM_INSTRUCTION_INSULT, SYSTEM_INSTRUCTION_VERIFY, SYSTEM_INSTRUCTION_PUNISHMENT } from "../constants";

// Helper to get AI instance safely
const getAI = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) throw new Error("API Key missing");
  return new GoogleGenAI({ apiKey });
};

export const generateInsult = async (profile: UserProfile, currentTask: string): Promise<InsultContent> => {
  try {
    const ai = getAI();

    // Generate Text Only
    const prompt = `
    User Profile:
    Name: ${profile.name}
    Major/Field: ${profile.major}
    Weakness: ${profile.weakness}
    Ambition: ${profile.ambition}
    Rival/Enemy: ${profile.enemy}
    Additional Context (Use this to be specific!): ${profile.additionalInfo}

    Current Task they should be doing: ${currentTask}

    Generate a brutal, personalized insult/threat.
    `;

    const textResponse = await ai.models.generateContent({
      model: 'gemini-2.5-flash',
      contents: prompt,
      config: {
        systemInstruction: SYSTEM_INSTRUCTION_INSULT,
        temperature: 1.2, 
      }
    });

    const insultText = textResponse.text || "You are wasting space. Get to work.";

    return {
      text: insultText,
    };

  } catch (error) {
    console.error("Insult gen failed:", error);
    return { text: "Work harder. The AI is judging your connection." };
  }
};

export const verifyTaskCompletion = async (task: string, proofDescription: string, proofImageBase64?: string): Promise<{success: boolean, message: string}> => {
    const ai = getAI();

    const parts: any[] = [{ text: `Task: ${task}. User Description: ${proofDescription}` }];
    if (proofImageBase64) {
        const data = proofImageBase64.replace(/^data:image\/\w+;base64,/, "");
        parts.push({ inlineData: { mimeType: 'image/jpeg', data } });
    }

    const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash',
        contents: { parts },
        config: {
            systemInstruction: SYSTEM_INSTRUCTION_VERIFY,
            responseMimeType: 'application/json',
            responseSchema: {
                type: Type.OBJECT,
                properties: {
                    success: { type: Type.BOOLEAN },
                    message: { type: Type.STRING }
                },
                required: ['success', 'message']
            }
        }
    });

    const json = JSON.parse(response.text || '{"success": false, "message": "Failed to verify"}');
    return json;
};

export const generatePunishment = async (): Promise<string> => {
    const ai = getAI();
    const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash',
        contents: "Give me a STATIC punishment pose.",
        config: {
            systemInstruction: SYSTEM_INSTRUCTION_PUNISHMENT,
        }
    });
    return response.text || "Hold a heavy book above your head.";
};

export const verifyPunishment = async (proofImageBase64: string): Promise<boolean> => {
     try {
        const ai = getAI();
        const data = proofImageBase64.replace(/^data:image\/\w+;base64,/, "");
        const response = await ai.models.generateContent({
        model: 'gemini-2.5-flash',
        contents: {
            parts: [
                { inlineData: { mimeType: 'image/jpeg', data } },
                { text: "Does this image show a person performing the requested static pose or looking humbled/punished? Answer YES or NO." }
            ]
        },
        config: { temperature: 0 }
        });

        const text = response.text?.trim().toUpperCase();
        return text?.includes("YES") || false;
    } catch (e) {
        return true; // Fail open
    }
}

