import React, { useState, useMemo } from 'react';
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, Cell } from 'recharts';
import { SessionData } from '../types';
import { X, Pin, PinOff, Calendar, Clock } from 'lucide-react';

interface StatsProps {
  history: SessionData[];
  onClose?: () => void;
  isPinned?: boolean;
  onTogglePin?: () => void;
  className?: string;
}

type TimeRange = 'week' | 'day';

export const Stats: React.FC<StatsProps> = ({ history, onClose, isPinned = false, onTogglePin, className = '' }) => {
  const [range, setRange] = useState<TimeRange>('week');

  const data = useMemo(() => {
    const now = Date.now();
    const filtered = history.filter(s => s.type === 'FOCUS' && s.completed);

    if (range === 'week') {
      const map: Record<string, number> = {};
      // Initialize last 7 days with 0
      for (let i = 6; i >= 0; i--) {
        const d = new Date(now - i * 24 * 60 * 60 * 1000);
        map[d.toLocaleDateString()] = 0;
      }

      filtered.forEach(s => {
        const d = new Date(s.timestamp).toLocaleDateString();
        if (map[d] !== undefined) map[d] += s.duration / 60;
      });

      return Object.entries(map).map(([date, minutes]) => ({
        label: date.split('/').slice(0, 2).join('/'), // MM/DD
        value: Math.round(minutes),
        fullDate: date
      }));
    } else {
      // Last 24 Hours
      const map: Record<string, number> = {};
      // Initialize last 24 hours
      for (let i = 23; i >= 0; i--) {
        const d = new Date(now - i * 60 * 60 * 1000);
        const hour = d.getHours();
        const label = `${hour}:00`;
        map[label] = 0;
      }

      filtered.forEach(s => {
        // Only count if within last 24h
        if (now - s.timestamp < 24 * 60 * 60 * 1000) {
            const d = new Date(s.timestamp);
            const label = `${d.getHours()}:00`;
            if (map[label] !== undefined) map[label] += s.duration / 60;
        }
      });

      return Object.entries(map).map(([label, minutes]) => ({
        label,
        value: Math.round(minutes)
      }));
    }
  }, [history, range]);

  const totalTime = useMemo(() => 
    Math.round(history.reduce((acc, s) => s.type === 'FOCUS' && s.completed ? acc + s.duration : acc, 0) / 60), 
  [history]);

  // View Variants
  if (isPinned) {
    return (
      <div className={`bg-black/40 backdrop-blur-sm border border-gray-800 rounded p-4 w-80 shadow-xl transition-all hover:bg-black/60 ${className}`}>
        <div className="flex justify-between items-center mb-2">
            <h3 className="text-xs font-bold text-gray-400 uppercase tracking-wider flex items-center gap-2">
                <Clock size={12} /> Focus Trend
            </h3>
            <div className="flex gap-1">
                <button onClick={() => setRange(range === 'week' ? 'day' : 'week')} className="text-[10px] uppercase px-1 py-0.5 bg-gray-800 rounded text-gray-300 hover:text-white">
                    {range === 'week' ? '7D' : '24H'}
                </button>
                {onTogglePin && (
                    <button onClick={onTogglePin} className="text-gray-500 hover:text-red-500">
                        <PinOff size={12} />
                    </button>
                )}
            </div>
        </div>
        <div className="h-32 w-full">
            <ResponsiveContainer width="100%" height="100%">
                <BarChart data={data}>
                    <Tooltip 
                        contentStyle={{ backgroundColor: '#000', border: '1px solid #333', fontSize: '10px' }}
                        itemStyle={{ color: '#fff' }}
                        cursor={{fill: 'rgba(255, 255, 255, 0.05)'}}
                    />
                    <Bar dataKey="value" fill="#ff0000" radius={[2, 2, 0, 0]} barSize={range === 'day' ? 6 : 12}>
                        {data.map((entry, index) => (
                            <Cell key={`cell-${index}`} fill={entry.value > 0 ? '#ff0000' : '#333'} />
                        ))}
                    </Bar>
                    <XAxis dataKey="label" hide />
                </BarChart>
            </ResponsiveContainer>
        </div>
        <div className="flex justify-between mt-2 text-[10px] text-gray-500 font-mono">
            <span>TOTAL: {totalTime} MINS</span>
            <span>{range === 'week' ? 'LAST 7 DAYS' : 'LAST 24 HOURS'}</span>
        </div>
      </div>
    );
  }

  // Modal View
  return (
    <div className="absolute inset-0 bg-void-black/95 z-[60] flex flex-col items-center justify-center p-8 backdrop-blur-md">
      <div className="w-full max-w-4xl bg-dim-gray border border-gray-700 p-6 rounded-lg shadow-2xl relative">
        {/* Header */}
        <div className="flex justify-between items-center mb-6 border-b border-gray-800 pb-4">
          <h2 className="text-2xl font-bold text-white uppercase tracking-wider flex items-center gap-2">
            <TrendingUpIcon size={24} className="text-danger-red" /> Performance Record
          </h2>
          <div className="flex gap-4 items-center">
            {onTogglePin && (
                <button onClick={onTogglePin} className="flex items-center gap-2 text-gray-400 hover:text-white uppercase text-xs tracking-widest border border-gray-700 px-3 py-2 rounded hover:border-gray-500 transition-colors">
                    <Pin size={14} /> Pin to Dashboard
                </button>
            )}
            <button onClick={onClose} className="text-gray-400 hover:text-white uppercase"><X size={24} /></button>
          </div>
        </div>

        {/* Controls */}
        <div className="flex gap-2 mb-6 justify-end">
            <button 
                onClick={() => setRange('day')}
                className={`px-4 py-2 rounded text-sm font-bold uppercase ${range === 'day' ? 'bg-danger-red text-white' : 'bg-gray-800 text-gray-400 hover:bg-gray-700'}`}
            >
                Last 24 Hours
            </button>
            <button 
                onClick={() => setRange('week')}
                className={`px-4 py-2 rounded text-sm font-bold uppercase ${range === 'week' ? 'bg-danger-red text-white' : 'bg-gray-800 text-gray-400 hover:bg-gray-700'}`}
            >
                Last 7 Days
            </button>
        </div>

        {/* Main Graph */}
        <div className="h-80 w-full mb-8 bg-black/20 rounded p-4 border border-gray-800/50">
            <ResponsiveContainer width="100%" height="100%">
            <BarChart data={data} margin={{ top: 20, right: 30, left: 20, bottom: 5 }}>
                <XAxis 
                    dataKey="label" 
                    stroke="#666" 
                    fontSize={12} 
                    tickLine={false} 
                    axisLine={false} 
                    interval={range === 'day' ? 2 : 0} // Skip labels on hourly view to avoid crowd
                />
                <YAxis stroke="#666" fontSize={12} tickLine={false} axisLine={false} unit="m" />
                <Tooltip 
                    contentStyle={{ backgroundColor: '#000', border: '1px solid #333' }}
                    itemStyle={{ color: '#fff' }}
                    cursor={{fill: 'rgba(255, 255, 255, 0.05)'}}
                    formatter={(value: number) => [`${value} mins`, 'Focus Time']}
                />
                <Bar dataKey="value" fill="#ff0000" radius={[4, 4, 0, 0]}>
                   {data.map((entry, index) => (
                      <Cell key={`cell-${index}`} fill={entry.value > 0 ? '#ff0000' : '#333'} />
                    ))}
                </Bar>
            </BarChart>
            </ResponsiveContainer>
        </div>

        {/* Footer Stats */}
        <div className="grid grid-cols-3 gap-4">
            <StatBox label="Total Focus Time" value={`${totalTime} mins`} />
            <StatBox label="Sessions Completed" value={history.filter(s => s.type === 'FOCUS' && s.completed).length.toString()} />
            <StatBox label="Completion Rate" value={`${Math.round((history.filter(s => s.type === 'FOCUS' && s.completed).length / (history.filter(s => s.type === 'FOCUS').length || 1)) * 100)}%`} />
        </div>
      </div>
    </div>
  );
};

