// --- Main App Component ---

const App: React.FC = () => {
  // --- State ---
  const [mode, setMode] = useState<AppMode>(AppMode.ONBOARDING);
  const [profile, setProfile] = useState<UserProfile | null>(null);
  const [config, setConfig] = useState<SessionConfig>(DEFAULT_CONFIG);
  const [timeLeft, setTimeLeft] = useState(DEFAULT_CONFIG.focusDuration * 60);
  const [isRunning, setIsRunning] = useState(false);
  const [sessionCount, setSessionCount] = useState(0);
  const [currentTask, setCurrentTask] = useState('');

  // UI State
  const [showSettings, setShowSettings] = useState(false);
  const [showStats, setShowStats] = useState(false);
  const [statsPinned, setStatsPinned] = useState(false);
  const [showExplain, setShowExplain] = useState(false);

  // Monitoring
  const [integrity, setIntegrity] = useState(100); // 0 - 100
  const videoRef = useRef<HTMLVideoElement>(null);
  const [cameraActive, setCameraActive] = useState(false);
  const [isVisionReady, setIsVisionReady] = useState(false);
  const [visionStatus, setVisionStatus] = useState<VisionStatus>({ isPresent: false, hasPhone: false, isSlouching: false });

  // Content
  const [insult, setInsult] = useState<InsultContent | null>(null);
  const [punishment, setPunishment] = useState<string>('');
  const [snapshotPreview, setSnapshotPreview] = useState<string | null>(null);
  const [loadingMessage, setLoadingMessage] = useState(false);

  // Verification
  const [verifyText, setVerifyText] = useState('');
  const [verificationLoading, setVerificationLoading] = useState(false);

  // Stats
  const [history, setHistory] = useState<SessionData[]>([]);

  // --- Effects ---

  // Load from storage
  useEffect(() => {
    const saved = localStorage.getItem('lock_in_data');
    if (saved) {
      const parsed = JSON.parse(saved);
      if (parsed.profile) {
        setProfile(parsed.profile);
        setMode(AppMode.IDLE);
      }
      if (parsed.history) setHistory(parsed.history);
      if (parsed.config) setConfig(parsed.config);
      if (parsed.statsPinned) setStatsPinned(parsed.statsPinned);
    }

    // Load Vision Model
    VisionService.loadModel().then(() => setIsVisionReady(true));
  }, []);

  // Save to storage
  useEffect(() => {
    if (profile) {
      localStorage.setItem('lock_in_data', JSON.stringify({ profile, history, config, statsPinned }));
    }
  }, [profile, history, config, statsPinned]);

  // Timer Tick
  useEffect(() => {
    let interval: any;
    if (isRunning && timeLeft > 0) {
      interval = setInterval(() => {
        setTimeLeft(prev => prev - 1);
      }, 1000);
    } else if (timeLeft === 0 && isRunning) {
      handleTimerComplete();
    }
    return () => clearInterval(interval);
  }, [isRunning, timeLeft]);

  // Attention Monitoring Logic (Local Models)
  useEffect(() => {
    if (mode !== AppMode.FOCUS || !isRunning || !isVisionReady) return;

    // 1. Vision Check Interval
    const checkInterval = setInterval(async () => {
        if (!videoRef.current) return;

        const status = await VisionService.monitorUser(videoRef.current);
        setVisionStatus(status);

        // 2. Integrity Logic - Direct State Update
        setIntegrity(prev => {
            let next = prev;

            // Logic: 
            // 1. Recover slowly if everything is good (+1 per second)
            // 2. Drain if bad.

            const isGood = status.isPresent && !status.hasPhone && !status.isSlouching;

            if (isGood) {
                // Recovery (Slow)
                next = Math.min(100, next + 1);
            } else {
                // Penalties
                let drain = 0;

                // Missing: Linear drain over 10s (approx 10 pts/sec)
                if (!status.isPresent) drain += 10;

                // Slouching: Linear drain over ~5s (20 pts/sec)
                if (status.isSlouching) drain += 5; 

                // Phone: Massive drain (Instakill in ~2s) (50 pts/sec)
                if (status.hasPhone) drain += 40;

                next = Math.max(0, next - drain);
            }
            return next;
        });

    }, 1000); // Check every second

    // 3. Alarm Trigger (Run more frequently for responsiveness)
    const alarmInterval = setInterval(() => {
        if (integrity <= 0) {
            playAlarm();
        } else {
            stopAlarm();
        }
    }, 200);

    return () => {
        clearInterval(checkInterval);
        clearInterval(alarmInterval);
        stopAlarm();
    };
  }, [mode, isRunning, isVisionReady, integrity]); // Added integrity to dep array for alarm check, safe? No, better use ref or check in setIntegrity. 
  // Actually, integrity in interval closure is stale.
  // Re-writing effect to be safer.

  // FIXED Monitoring Effect to handle stale state
  useEffect(() => {
      if (mode !== AppMode.FOCUS || !isRunning || !isVisionReady) return;

      const timer = setInterval(async () => {
         if (!videoRef.current) return;
         const status = await VisionService.monitorUser(videoRef.current);
         setVisionStatus(status);

         setIntegrity(prev => {
             let next = prev;
             const isGood = status.isPresent && !status.hasPhone && !status.isSlouching;

             if (isGood) next = Math.min(100, next + 2); // Recover
             else {
                 if (!status.isPresent) next -= 10; // 10s grace
                 if (status.isSlouching) next -= 15; // Fast warning
                 if (status.hasPhone) next -= 50; // INSTANT REGRET
             }
             const final = Math.max(0, next);

             // Side Effect: Audio (Safe here because we have the calculated 'final')
             if (final <= 0) playAlarm();
             else stopAlarm();

             return final;
         });
      }, 1000);

      return () => {
          clearInterval(timer);
          stopAlarm();
      };
  }, [mode, isRunning, isVisionReady]);


  // Initial Insult
  useEffect(() => {
    if (mode === AppMode.FOCUS && isRunning && profile && !insult) {
       generateNewInsult();
    }
  }, [mode, isRunning, profile]);

  // --- Handlers ---

  const generateNewInsult = async () => {
      if(!profile) return;
      setLoadingMessage(true);
      const content = await GeminiService.generateInsult(profile, currentTask);
      setInsult(content);
      setLoadingMessage(false);
  };

  const startCamera = async () => {
    try {
        const stream = await navigator.mediaDevices.getUserMedia({ video: { width: 320, height: 240 } });
        if (videoRef.current) {
            videoRef.current.srcObject = stream;
            // Wait for video to be ready
            videoRef.current.onloadedmetadata = () => {
               videoRef.current?.play();
               setCameraActive(true);
            }
        }
    } catch (e) {
        alert("Camera required for monitoring. Enable it.");
    }
  };

  const handleStartSession = async () => {
    if (!currentTask.trim()) {
        alert("State your task. Don't hide.");
        return;
    }
    if (!cameraActive) await startCamera();

    setMode(AppMode.FOCUS);
    setTimeLeft(config.focusDuration * 60);
    setIsRunning(true);
    setIntegrity(100);
    setSnapshotPreview(null);
  };

  const handleTimerComplete = () => {
    setIsRunning(false);
    stopAlarm();

    if (mode === AppMode.FOCUS) {
        // Complete the session
        const nextSessionCount = sessionCount + 1;
        setSessionCount(nextSessionCount);

        setHistory(prev => [...prev, {
            timestamp: Date.now(),
            duration: config.focusDuration * 60,
            type: 'FOCUS',
            completed: true,
            task: currentTask
        }]);

        if (nextSessionCount >= config.sessionsBeforeLongBreak) {
            // End of Cycle -> Verify
            setMode(AppMode.VERIFY_TASK);
            setSessionCount(0); 
        } else {
            // Short break
            setMode(AppMode.BREAK_SHORT);
            setTimeLeft(config.shortBreakDuration * 60);
            setIsRunning(true);
        }
    } else if (mode === AppMode.BREAK_SHORT) {
        // Short break over -> Auto start next focus
        setMode(AppMode.FOCUS);
        setTimeLeft(config.focusDuration * 60);
        setIsRunning(true);
        setIntegrity(100);
        // Generate new insult for new session
        generateNewInsult();
    } else if (mode === AppMode.BREAK_LONG) {
        // Long break over -> Reset to IDLE
        setMode(AppMode.IDLE);
    }
  };

  const handleSkip = () => {
      handleTimerComplete();
  };

  const adjustTimer = (seconds: number) => {
      setTimeLeft(prev => Math.max(0, prev + seconds));
  };

  const captureWebcam = (): string | null => {
      if (!videoRef.current) return null;
      const canvas = document.createElement('canvas');
      canvas.width = 320;
      canvas.height = 240;
      const ctx = canvas.getContext('2d');
      ctx?.drawImage(videoRef.current, 0, 0);
      return canvas.toDataURL('image/jpeg');
  };

  const handleVerification = async (hasImage: boolean, imageData?: string) => {
      setVerificationLoading(true);
      try {
          const result = await GeminiService.verifyTaskCompletion(currentTask, verifyText, imageData);
          if (result.success) {
              setMode(AppMode.BREAK_LONG);
              setTimeLeft(config.longBreakDuration * 60);
              setIsRunning(true);
          } else {
              // Fail
              const punishmentTask = await GeminiService.generatePunishment();
              setPunishment(punishmentTask);
              setMode(AppMode.PUNISHMENT);
          }
      } catch (e) {
          alert("Error verifying. I'll let it slide this time because I'm broken.");
          setMode(AppMode.BREAK_LONG);
          setTimeLeft(config.longBreakDuration * 60);
          setIsRunning(true);
      }
      setVerificationLoading(false);
      setSnapshotPreview(null);
  };

  const handlePunishmentVerify = async () => {
     if (!snapshotPreview) {
         const img = captureWebcam();
         if(img) setSnapshotPreview(img);
         return; 
     }

     setVerificationLoading(true);
     const valid = await GeminiService.verifyPunishment(snapshotPreview);
     setVerificationLoading(false);

     if (valid) {
         setHistory(prev => [...prev, {
            timestamp: Date.now(),
            duration: config.focusDuration * 60,
            type: 'FOCUS',
            completed: false, 
            task: currentTask
        }]);
         setMode(AppMode.BREAK_LONG);
         setTimeLeft(config.longBreakDuration * 60);
         setIsRunning(true);
         setSnapshotPreview(null);
     } else {
         alert("That didn't look like punishment. Do it again.");
         setSnapshotPreview(null); 
     }
  };

  const handleSaveSettings = (newConfig: SessionConfig) => {
      setConfig(newConfig);
      setShowSettings(false);
  };

  const toggleStatsPin = () => {
      setStatsPinned(prev => !prev);
      if (showStats) setShowStats(false); // Close modal if pinning
  };

  // --- Render Helpers ---

  const formatTime = (seconds: number) => {
    const m = Math.floor(seconds / 60).toString().padStart(2, '0');
    const s = (seconds % 60).toString().padStart(2, '0');
    return `${m}:${s}`;
  };

  // --- Views ---

  if (mode === AppMode.ONBOARDING) {
      return <Onboarding onComplete={(p) => { setProfile(p); setMode(AppMode.IDLE); }} />;
  }

  return (
    <div className="relative min-h-screen w-full flex flex-col bg-void-black text-white transition-colors duration-200 overflow-hidden">

        {/* WEBCAM MONITORING UI */}
        <div className={`fixed bottom-6 right-6 z-50 transition-all duration-500 ease-in-out ${mode === AppMode.FOCUS ? 'opacity-100 translate-y-0' : 'opacity-0 translate-y-10 pointer-events-none'}`}>
             <div className="relative group w-72 bg-black border-2 border-gray-800 rounded-lg overflow-hidden shadow-2xl">
                {/* Video Feed */}
                <video ref={videoRef} autoPlay muted playsInline className="w-full h-48 object-cover opacity-60 group-hover:opacity-100 transition-opacity" />

                {/* Integrity Meter Overlay */}
                <div className="absolute bottom-0 left-0 w-full h-1 bg-gray-800">
                    <div 
                        className={`h-full transition-all duration-300 ${integrity < 30 ? "bg-red-600 animate-pulse-fast" : "bg-green-600"}`}
                        style={{ width: `${integrity}%` }}
                    />
                </div>

                {/* Status Text Overlay */}
                <div className="absolute top-2 left-2 flex flex-col gap-1 items-start">
                    <div className="bg-black/70 px-2 py-1 rounded text-[10px] font-bold uppercase flex items-center gap-2 backdrop-blur-sm">
                        <div className={`w-2 h-2 rounded-full ${integrity < 30 ? "bg-red-500 animate-ping" : "bg-green-500"}`} />
                        {integrity < 30 ? "CRITICAL FAILURE" : "MONITORING ACTIVE"}
                    </div>

                    {/* Granular Warnings */}
                    {visionStatus.hasPhone && (
                        <div className="bg-red-600 px-2 py-1 rounded text-[10px] font-bold uppercase animate-pulse flex items-center gap-1">
                            <Smartphone size={10} /> PHONE DETECTED
                        </div>
                    )}
                    {visionStatus.isSlouching && (
                        <div className="bg-yellow-600 px-2 py-1 rounded text-[10px] font-bold uppercase animate-pulse flex items-center gap-1">
                            <User size={10} /> SIT UP STRAIGHT
                        </div>
                    )}
                    {!visionStatus.isPresent && integrity < 90 && (
                        <div className="bg-orange-600 px-2 py-1 rounded text-[10px] font-bold uppercase animate-pulse flex items-center gap-1">
                            <Eye size={10} /> FACE MISSING
                        </div>
                    )}
                </div>

                {/* Explanation Toggle */}
                <button 
                    className="absolute top-2 right-2 text-gray-400 hover:text-white bg-black/50 rounded-full p-1"
                    onClick={() => setShowExplain(!showExplain)}
                >
                    <HelpCircle size={16} />
                </button>

                {/* Explanation Tooltip */}
                {showExplain && (
                    <div className="absolute inset-0 bg-black/95 p-4 text-xs text-gray-300 flex flex-col justify-center animate-fade-in backdrop-blur-sm">
                        <strong className="text-white uppercase mb-2 block">Monitoring Rules:</strong>
                        <ul className="list-disc pl-4 space-y-2 mb-2">
                            <li className="text-red-400"><strong>NO PHONES:</strong> Instant penalty.</li>
                            <li className="text-yellow-400"><strong>NO SLOUCHING:</strong> Sit upright. Don't lean back or slide down.</li>
                            <li><strong>FACE VISIBLE:</strong> Don't leave the chair.</li>
                        </ul>
                        <button onClick={() => setShowExplain(false)} className="mt-2 text-center w-full text-danger-red font-bold uppercase">Close</button>
                    </div>
                )}
             </div>
        </div>

        {/* Header */}
        <header className="p-6 flex justify-between items-center z-10 border-b border-gray-900 bg-void-black/80 backdrop-blur">
            <h1 className="text-2xl font-black tracking-widest text-danger-red italic">LOCK IN</h1>
            <div className="flex gap-4">
                <button onClick={() => setShowSettings(true)} className="p-2 hover:bg-gray-800 rounded text-gray-400 hover:text-white transition-colors">
                    <SettingsIcon size={24} />
                </button>
                <button onClick={() => setShowStats(true)} className="p-2 hover:bg-gray-800 rounded text-gray-400 hover:text-white transition-colors">
                    <TrendingUp size={24} />
                </button>
            </div>
        </header>

        {/* PINNED STATS WIDGET */}
        {statsPinned && !showStats && mode !== AppMode.ONBOARDING && (
            <div className="fixed top-24 left-6 z-40 animate-fade-in">
                <Stats 
                    history={history} 
                    isPinned={true} 
                    onTogglePin={toggleStatsPin}
                />
            </div>
        )}

        {/* Main Content Area */}
        <main className="flex-1 flex flex-col items-center justify-center p-6 relative">

            {/* IDLE VIEW */}
            {mode === AppMode.IDLE && (
                <div className="w-full max-w-md space-y-8 animate-fade-in">
                    <div className="text-center space-y-2">
                        <p className="text-gray-400">Welcome back, <span className="text-white font-bold">{profile?.name}</span>.</p>
                        <p className="text-sm text-gray-500">Ready to stop disappointing your ancestors?</p>
                    </div>

                    <div className="space-y-4">
                        <label className="block text-sm font-bold uppercase text-gray-500">Task Objective (Cycle Goal)</label>
                        <textarea 
                            value={currentTask}
                            onChange={(e) => setCurrentTask(e.target.value)}
                            placeholder="What exactly will you accomplish in this cycle? Be specific."
                            className="w-full bg-dim-gray border border-gray-700 p-4 rounded text-white focus:border-danger-red outline-none min-h-[100px]"
                        />
                    </div>

                    <button 
                        onClick={handleStartSession}
                        className="w-full bg-danger-red hover:bg-red-700 text-white font-black py-6 rounded text-xl uppercase tracking-widest shadow-[0_0_20px_rgba(255,0,0,0.3)] hover:shadow-[0_0_30px_rgba(255,0,0,0.5)] transition-all"
                    >
                        INITIATE PROTOCOL
                    </button>
                </div>
            )}

            {/* FOCUS VIEW */}
            {mode === AppMode.FOCUS && (
                <div className="w-full h-full flex flex-col items-center justify-center relative gap-8 max-w-4xl mx-auto">

                    {/* Timer with Dynamic Controls */}
                    <div className="text-center group relative">
                         <div className="text-[10rem] md:text-[12rem] font-black leading-none tracking-tighter tabular-nums drop-shadow-2xl text-white">
                             {formatTime(timeLeft)}
                         </div>
                         <div className="absolute top-1/2 -right-12 -translate-y-1/2 flex flex-col gap-2 opacity-0 group-hover:opacity-100 transition-opacity">
                            <button onClick={() => adjustTimer(60)} className="bg-gray-800 p-2 rounded hover:bg-gray-700 hover:text-green-400"><Plus size={24}/></button>
                            <button onClick={() => adjustTimer(-60)} className="bg-gray-800 p-2 rounded hover:bg-gray-700 hover:text-red-400"><Minus size={24}/></button>
                         </div>
                         <div className="text-red-500 font-bold uppercase tracking-[1em] animate-pulse">
                             Focusing (Session {sessionCount + 1}/{config.sessionsBeforeLongBreak})
                         </div>
                    </div>

                    {/* Content Area - Text Only */}
                    <div className="w-full max-w-3xl flex flex-col items-center gap-6">
                         {/* Insult Card - Large Typography */}
                        <div className="w-full bg-dim-gray/80 border-x-4 border-danger-red p-8 rounded shadow-2xl backdrop-blur relative min-h-[160px] flex items-center justify-center text-center">
                            {insult ? (
                                <p className="text-2xl md:text-4xl font-black text-gray-200 leading-tight uppercase font-mono tracking-wide">
                                    "{insult.text}"
                                </p>
                            ) : (
                                <p className="text-gray-500 animate-pulse text-xl">Constructing Psychological Attack...</p>
                            )}
                            <button 
                                onClick={generateNewInsult} 
                                disabled={loadingMessage}
                                className="absolute top-2 right-2 text-gray-600 hover:text-white p-2"
                                title="Get new motivation"
                            >
                                <RefreshCw size={20} className={loadingMessage ? "animate-spin" : ""} />
                            </button>
                        </div>
                    </div>

                    <button 
                        onClick={handleSkip}
                        className="mt-8 text-gray-600 hover:text-red-500 text-sm uppercase tracking-widest flex items-center gap-2 transition-colors"
                    >
                        <SkipForward size={16} />
                        Skip (Coward's Way Out)
                    </button>
                </div>
            )}

            {/* BREAK VIEW */}
            {(mode === AppMode.BREAK_SHORT || mode === AppMode.BREAK_LONG) && (
                <div className="text-center z-10">
                     <h2 className="text-4xl font-bold text-green-500 mb-4">REST PROTOCOL</h2>
                     <div className="text-9xl font-mono mb-8">{formatTime(timeLeft)}</div>
                     <p className="text-gray-400 max-w-md mx-auto mb-8">
                         Don't get comfortable. The next session will be harder. 
                         {mode === AppMode.BREAK_LONG ? " Enjoy your long break." : " Just a quick sip of water."}
                     </p>

                     <button 
                        onClick={handleSkip}
                        className="bg-gray-800 hover:bg-gray-700 text-white px-6 py-3 rounded uppercase tracking-wider transition-colors"
                    >
                        Skip Break (Start Suffering)
                    </button>
                </div>
            )}

            {/* VERIFICATION VIEW */}
            {mode === AppMode.VERIFY_TASK && (
                 <div className="w-full max-w-md bg-dim-gray p-8 rounded border border-gray-700 space-y-6 z-10">
                     <h2 className="text-2xl font-bold text-white uppercase text-center border-b border-gray-700 pb-4">Cycle Complete</h2>
                     <p className="text-gray-400 text-sm">Prove you accomplished your goal during this cycle.</p>

                     <div>
                         <label className="block text-xs uppercase text-gray-500 mb-1">Summary of accomplishments</label>
                         <textarea 
                            className="w-full bg-void-black border border-gray-800 p-3 rounded text-white h-32"
                            value={verifyText}
                            onChange={e => setVerifyText(e.target.value)}
                         />
                     </div>

                     <div className="grid grid-cols-2 gap-2">
                         <button 
                             onClick={() => {
                                 const input = document.createElement('input');
                                 input.type = 'file';
                                 input.accept = 'image/*';
                                 input.onchange = (e) => {
                                     const file = (e.target as HTMLInputElement).files?.[0];
                                     if(file) {
                                         const reader = new FileReader();
                                         reader.onloadend = () => handleVerification(true, reader.result as string);
                                         reader.readAsDataURL(file);
                                     }
                                 };
                                 input.click();
                             }}
                             disabled={verificationLoading}
                             className="bg-gray-700 hover:bg-gray-600 py-3 rounded flex items-center justify-center gap-2 text-xs"
                         >
                             <Camera size={14} /> Upload File
                         </button>
                         <button 
                             onClick={() => {
                                 const img = captureWebcam();
                                 if(img) handleVerification(true, img);
                             }}
                             disabled={verificationLoading}
                             className="bg-gray-700 hover:bg-gray-600 py-3 rounded flex items-center justify-center gap-2 text-xs"
                         >
                             <Eye size={14} /> Use Webcam
                         </button>
                     </div>
                     <button 
                        onClick={() => handleVerification(false)}
                        disabled={verificationLoading}
                        className="w-full bg-blue-900 hover:bg-blue-800 py-3 rounded text-blue-100"
                     >
                         Verify with Text Only
                     </button>

                     {verificationLoading && <div className="text-center text-danger-red animate-pulse">JUDGING YOU...</div>}
                 </div>
            )}

            {/* PUNISHMENT VIEW */}
            {mode === AppMode.PUNISHMENT && (
                 <div className="w-full max-w-lg bg-red-950/50 border-4 border-danger-red p-8 rounded text-center z-10">
                     <h2 className="text-3xl font-black text-white mb-6 uppercase">FAILURE DETECTED</h2>
                     <p className="text-red-200 mb-8 text-xl font-mono">{punishment}</p>

                     <div className="bg-black/50 p-4 rounded mb-6">
                         {snapshotPreview ? (
                             <div className="space-y-4">
                                <img src={snapshotPreview} alt="Proof" className="w-full rounded border border-gray-600" />
                                <div className="flex gap-2">
                                     <button 
                                         onClick={() => setSnapshotPreview(null)}
                                         className="flex-1 bg-gray-700 hover:bg-gray-600 py-2 rounded"
                                     >Retake</button>
                                     <button 
                                         onClick={handlePunishmentVerify}
                                         className="flex-1 bg-danger-red hover:bg-red-600 text-white font-bold py-2 rounded"
                                     >Submit Proof</button>
                                </div>
                             </div>
                         ) : (
                             <>
                                <p className="text-sm text-gray-400 mb-4">Perform the punishment in front of the camera.</p>
                                <button 
                                     onClick={() => {
                                         const img = captureWebcam();
                                         if(img) setSnapshotPreview(img);
                                     }}
                                     disabled={verificationLoading}
                                     className="w-full bg-danger-red hover:bg-red-600 text-white font-bold py-4 rounded uppercase"
                                 >
                                     CAPTURE SNAPSHOT
                                 </button>
                             </>
                         )}
                         {verificationLoading && <p className="mt-2 text-red-400 animate-pulse">ANALYZING...</p>}
                     </div>
                 </div>
            )}
        </main>

        {/* Modals */}
        {showSettings && (
            <SettingsModal 
                config={config} 
                onSave={handleSaveSettings} 
                onClose={() => setShowSettings(false)} 
            />
        )}
        {showStats && (
            <Stats 
                history={history} 
                onClose={() => setShowStats(false)} 
                onTogglePin={toggleStatsPin}
                isPinned={false}
            />
        )}
    </div>
  );
};

export default App;

export enum AppMode {
  ONBOARDING = 'ONBOARDING',
  IDLE = 'IDLE',
  FOCUS = 'FOCUS',
  BREAK_SHORT = 'BREAK_SHORT',
  BREAK_LONG = 'BREAK_LONG',
  VERIFY_TASK = 'VERIFY_TASK',
  PUNISHMENT = 'PUNISHMENT',
  SETTINGS = 'SETTINGS',
}

