                    <button onClick={onClose}><X className="text-gray-400 hover:text-white"/></button>
                </div>

                {/* Tabs */}
                <div className="flex border-b border-gray-700 mb-6">
                    <button 
                        onClick={() => setActiveTab('protocol')}
                        className={`flex-1 pb-2 text-sm font-bold uppercase tracking-wider ${activeTab === 'protocol' ? 'text-danger-red border-b-2 border-danger-red' : 'text-gray-500 hover:text-gray-300'}`}
                    >
                        Protocol
                    </button>
                    <button 
                        onClick={() => setActiveTab('appearance')}
                        className={`flex-1 pb-2 text-sm font-bold uppercase tracking-wider ${activeTab === 'appearance' ? 'text-danger-red border-b-2 border-danger-red' : 'text-gray-500 hover:text-gray-300'}`}
                    >
                        Appearance
                    </button>
                </div>

                <div className="overflow-y-auto flex-1 pr-2 space-y-6">
                    {activeTab === 'protocol' ? (
                        <div className="space-y-4">
                            <div>
                                <label className="text-xs uppercase text-gray-400 block mb-1">Focus Duration (min)</label>
                                <input 
                                    type="number" 
                                    value={localConfig.focusDuration}
                                    onChange={e => setLocalConfig({...localConfig, focusDuration: parseInt(e.target.value) || 25})}
                                    className="w-full bg-void-black border border-gray-600 rounded p-2 text-white focus:border-danger-red outline-none"
                                />
                            </div>
                            <div>
                                <label className="text-xs uppercase text-gray-400 block mb-1">Short Break (min)</label>
                                <input 
                                    type="number" 
                                    value={localConfig.shortBreakDuration}
                                    onChange={e => setLocalConfig({...localConfig, shortBreakDuration: parseInt(e.target.value) || 5})}
                                    className="w-full bg-void-black border border-gray-600 rounded p-2 text-white focus:border-danger-red outline-none"
                                />
                            </div>
                            <div>
                                <label className="text-xs uppercase text-gray-400 block mb-1">Long Break (min)</label>
                                <input 
                                    type="number" 
                                    value={localConfig.longBreakDuration}
                                    onChange={e => setLocalConfig({...localConfig, longBreakDuration: parseInt(e.target.value) || 15})}
                                    className="w-full bg-void-black border border-gray-600 rounded p-2 text-white focus:border-danger-red outline-none"
                                />
                            </div>
                            <div>
                                <label className="text-xs uppercase text-gray-400 block mb-1">Sessions Before Long Break</label>
                                <input 
                                    type="number" 
                                    value={localConfig.sessionsBeforeLongBreak}
                                    onChange={e => setLocalConfig({...localConfig, sessionsBeforeLongBreak: parseInt(e.target.value) || 4})}
                                    className="w-full bg-void-black border border-gray-600 rounded p-2 text-white focus:border-danger-red outline-none"
                                />
                            </div>
                        </div>
                    ) : (
                        <div className="space-y-6">
                            {/* Presets */}
                            <div>
                                <label className="text-xs uppercase text-gray-400 block mb-2">Presets</label>
                                <div className="grid grid-cols-2 gap-2">
                                    {Object.values(THEME_PRESETS).map(preset => (
                                        <button 
                                            key={preset.id}
                                            onClick={() => setLocalTheme(preset)}
                                            className={`p-2 rounded text-xs font-bold uppercase border transition-all ${
                                                localTheme.id === preset.id 
                                                ? 'border-danger-red bg-void-black text-white' 
                                                : 'border-gray-700 bg-black/20 text-gray-400 hover:border-gray-500'
                                            }`}
                                        >
                                            {preset.name}
                                        </button>
                                    ))}
                                </div>
                            </div>

                            {/* Manual Overrides */}
                            <div className="space-y-3 pt-4 border-t border-gray-700">
                                <label className="text-xs uppercase text-gray-400 block">Custom Colors</label>

                                <div className="flex items-center justify-between">
                                    <span className="text-sm text-gray-300">Accent Color</span>
                                    <input 
                                        type="color" 
                                        value={localTheme.colors.accent}
                                        onChange={(e) => setLocalTheme({
                                            ...localTheme, 
                                            id: 'custom', 
                                            colors: { ...localTheme.colors, accent: e.target.value }
                                        })}
                                        className="bg-transparent h-8 w-12 cursor-pointer"
                                    />
                                </div>
                                <div className="flex items-center justify-between">
                                    <span className="text-sm text-gray-300">Background</span>
                                    <input 
                                        type="color" 
                                        value={localTheme.colors.bg}
                                        onChange={(e) => setLocalTheme({
                                            ...localTheme, 
                                            id: 'custom', 
                                            colors: { ...localTheme.colors, bg: e.target.value }
                                        })}
                                        className="bg-transparent h-8 w-12 cursor-pointer"
                                    />
                                </div>

                                <div>
                                    <label className="text-xs uppercase text-gray-400 block mb-1 mt-2">Font Family</label>
                                    <select 
                                        value={localTheme.font}
                                        onChange={(e) => setLocalTheme({
                                            ...localTheme, 
                                            id: 'custom', 
                                            font: e.target.value
                                        })}
                                        className="w-full bg-void-black border border-gray-600 rounded p-2 text-xs text-white outline-none"
                                    >
                                        <option value="ui-monospace, SFMono-Regular, Menlo, Monaco, Consolas, monospace">Monospace (Default)</option>
                                        <option value="Arial, sans-serif">Sans Serif (Arial)</option>
                                        <option value="'Times New Roman', serif">Serif (Times)</option>
                                        <option value="'Courier New', Courier, monospace">Retro Courier</option>
                                    </select>
                                </div>
                            </div>
                        </div>
                    )}
                </div>

                <button 
                    onClick={() => {
                        onSaveConfig(localConfig);
                        onSaveTheme(localTheme);
                    }}
                    className="w-full bg-danger-red hover:bg-red-700 text-white font-bold py-3 rounded mt-6 uppercase transition-colors"
                >
                    Apply Changes
                </button>
            </div>
        </div>
    );
}

