                                        type="checkbox" 
                                        checked={localConfig.enableGemini ?? true} 
                                        onChange={e => setLocalConfig({...localConfig, enableGemini: e.target.checked})}
                                        className="w-5 h-5 accent-danger-red"
                                    />
