                                <p className="text-[10px] text-main/50 mt-1">
                                    Controls AI Insults, Verification, and Punishments. Vision monitoring is always active.
                                </p>
                            </div>
                        </div>
                    ) : (
                        <div className="space-y-6">
                            {/* Presets */}
